(()=>{'use strict';
const T=v=>String(v??'').trim();
const NUM=v=>Number(String(v??'').replace(/,/g,'').replace(/[^0-9.\-]/g,''))||0;
const B=n=>NUM(n).toLocaleString('th-TH',{minimumFractionDigits:2,maximumFractionDigits:2});
function cleanPs(v){const p=T(v).split(/\s+/).filter(Boolean);if(!p.length)return'';if(p.length===2&&p[0]===p[1])return p[0];const out=[];p.forEach(x=>{if(!out.includes(x))out.push(x)});return out.join(' ')}
function esc(s){return T(s).replace(/[&<>"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c]))}
function rows(){const c=[window.__doitStableRows311,window.__doitRawRows304,window.__doitRawRows290,window.__doitPsRawRows295,window.__doitAllRows,window.__doitCoreRows];for(const r of c){if(Array.isArray(r)&&r.length)return r}return[]}
function psList(){const g=(window.DOIT_SELECTED_PS_LIST||[]).map(cleanPs).filter(Boolean);if(g.length)return [...new Set(g)];const v=cleanPs(document.querySelector('#psSelect')?.value);return v?[v]:[]}
function dateList(){return [...new Set((window.DOIT_SELECTED_DATES||[]).map(T).filter(Boolean))]}
function dateOk(r,ds,start,end){const d=T(r.date||r.raw?.date||r.raw?.InvcDate||r.raw?.InvoiceDate||r.raw?.Invoice_Date);if(ds.length)return ds.includes(d);if(start&&d<start)return false;if(end&&d>end)return false;return true}
function psOk(r,ps){if(!ps.length)return true;return ps.includes(cleanPs(r.ps||r.personKey||r.salespersonId||r.salespersonName||r.raw?.SalespersonID||r.raw?.SO_SalespersonID||r.raw?.Salesperson_Name))}
function storeOf(r){return T(r.store||r.customerName||r.storeName||r.raw?.['Customer Name']||r.raw?.CustomerName||r.raw?.ShipName||r.raw?.Store||r.raw?.StoreName||r.raw?.ShipToName)}
function updateStoreOptions(){const el=document.querySelector('#storeSelect');const rs=rows();if(!el||!rs.length)return false;const cur=T(el.value),ps=psList(),ds=dateList(),start=T(document.querySelector('#startDate')?.value),end=T(document.querySelector('#endDate')?.value);const stores=[...new Set(rs.filter(r=>dateOk(r,ds,start,end)&&psOk(r,ps)).map(storeOf).filter(Boolean))].sort((a,b)=>a.localeCompare(b,'th'));if(!stores.length)return false;el.innerHTML='<option value="">เลือกร้านจริง</option>'+stores.map(x=>`<option value="${esc(x)}">${esc(x)}</option>`).join('');if(cur&&stores.includes(cur))el.value=cur;return true}
function syncPsFromSelect(){const el=document.querySelector('#psSelect');const v=cleanPs(el?.value);if(v){window.DOIT_SELECTED_PS_LIST=[v];window.DOIT_SELECTED_PS_KEY=v}}
function headIndex(ths,label){return ths.findIndex(th=>T(th.textContent).replace(/\s+/g,'')===label)}
function patchGrossVatTable(){const table=document.querySelector('#table');if(!table||table.__grossVatBusy)return false;const tr=table.querySelector('thead tr'),tb=table.querySelector('tbody');if(!tr||!tb)return false;const ths=[...tr.children],rawIdx=headIndex(ths,'ยอดดิบ'),netIdx=headIndex(ths,'ยอดสุทธิ');if(rawIdx<0||netIdx<0)return false;table.__grossVatBusy=true;try{if(!ths.some(th=>T(th.textContent).replace(/\s+/g,'')==='รวมVAT')){const th=document.createElement('th');th.textContent='รวม VAT';tr.appendChild(th)}[...tb.rows].forEach(row=>{const empty=row.querySelector('.empty');if(empty){const c=row.querySelector('td[colspan]');if(c)c.colSpan=Math.max(NUM(c.colSpan),ths.length+1);return}const cells=[...row.children];if(!cells[rawIdx]||!cells[netIdx])return;const raw=NUM(cells[rawIdx]?.innerText),net=NUM(cells[netIdx]?.innerText),base=net>0?net:raw;let last=row.lastElementChild;if(!last||last.dataset.grossVat!=='1'){last=document.createElement('td');last.dataset.grossVat='1';row.appendChild(last)}last.textContent=B(base*1.07)})}finally{table.__grossVatBusy=false}return true}
function patchGrossVatSummary(){const el=document.querySelector('#amount');if(!el)return false;const s=T(el.textContent);if(!/สุทธิ\s*฿/.test(s)||/รวม VAT/.test(s))return false;const m=s.match(/สุทธิ\s*฿\s*([0-9,]+(?:\.\d+)?)/);if(!m)return false;const base=NUM(m[1]);if(!base)return false;el.textContent=s+' / รวม VAT ฿ '+B(base*1.07);return true}
function updateVat(){return !!(patchGrossVatTable()|patchGrossVatSummary())}
function boot(){updateStoreOptions();updateVat();document.addEventListener('change',e=>{if(e.target?.id==='psSelect'){syncPsFromSelect();setTimeout(updateStoreOptions,0);setTimeout(updateStoreOptions,200)}if(['startDate','endDate'].includes(e.target?.id))setTimeout(updateStoreOptions,100)},true);document.addEventListener('input',()=>setTimeout(updateVat,0),true);document.addEventListener('click',()=>setTimeout(updateVat,80),true);['doit:scopeRendered','doit:psChanged','doit:selectedDatesChanged'].forEach(ev=>document.addEventListener(ev,()=>{setTimeout(updateStoreOptions,80);setTimeout(updateVat,100)}));try{new MutationObserver(()=>setTimeout(updateVat,0)).observe(document.body,{childList:true,subtree:true})}catch{}let n=0;const tick=()=>{updateStoreOptions();updateVat();if(++n<60)setTimeout(tick,300)};setTimeout(tick,200)}
window.DOIT_STORE_PS_FIX={version:'v334-gross-vat',update:updateStoreOptions,updateVat,health:()=>({rows:rows().length,ps:psList(),updated:updateStoreOptions(),grossVat:updateVat()})};
if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',boot);else boot();
})();